/**
 * @summary Get replies for a letter (admin)
 */
export const getGetLetterRepliesUrl = (letterId: string) => {
  return `/api/replies/${letterId}`;
};

export const getLetterReplies = async (
  letterId: string,
  options?: RequestInit,
): Promise<ReplyListResponse> => {
  return customFetch<ReplyListResponse>(getGetLetterRepliesUrl(letterId), {
    ...options,
    method: "GET",
  });
};

export const getGetLetterRepliesQueryKey = (letterId: string) => {
  return [`/api/replies/${letterId}`] as const;
};

export const getGetLetterRepliesQueryOptions = <
  TData = Awaited<ReturnType<typeof getLetterReplies>>,
  TError = ErrorType<unknown>,
>(
  letterId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getLetterReplies>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetLetterRepliesQueryKey(letterId);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getLetterReplies>>
  > = ({ signal }) => getLetterReplies(letterId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!letterId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getLetterReplies>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetLetterRepliesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getLetterReplies>>
>;
export type GetLetterRepliesQueryError = ErrorType<unknown>;

